Here's a modern MSTest data-driven test example for your `PriceCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // --- DataRow: inline constant values ---

    [TestMethod]
    [DataRow(1, 10.00, 10.00)]
    [DataRow(5, 3.50, 17.50)]
    [DataRow(0, 99.99, 0.00)]
    [DataRow(100, 0.01, 1.00)]
    public void CalculateTotal_ReturnsExpected(int quantity, double unitPrice, double expected)
    {
        var result = _calculator.CalculateTotal(quantity, (decimal)unitPrice);
        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(100.00, 0.10, 90.00)]   // 10% off
    [DataRow(100.00, 0.00, 100.00)]  // no discount
    [DataRow(50.00, 0.50, 25.00)]    // 50% off
    [DataRow(0.00, 0.25, 0.00)]      // zero price
    public void ApplyDiscount_ReturnsExpected(double price, double discount, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discount);
        Assert.AreEqual((decimal)expected, result);
    }

    // --- DynamicData: complex/non-constant scenarios ---

    [TestMethod]
    [DynamicData(nameof(BulkDiscountCases), DynamicDataSourceType.Method)]
    public void ApplyDiscount_BulkScenarios(decimal price, decimal discount, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discount);
        Assert.AreEqual(expected, result);
    }

    private static IEnumerable<object[]> BulkDiscountCases()
    {
        yield return new object[] { 999.99m, 0.15m, 849.99m };
        yield return new object[] { 1000.00m, 0.20m, 800.00m };
        yield return new object[] { 0.01m, 1.00m, 0.00m };  // 100% off
    }

    // --- DynamicData with DisplayName for readable test names ---

    [TestMethod]
    [DynamicData(nameof(EdgeCases), DynamicDataSourceType.Property,
        DynamicDataDisplayName = nameof(GetDisplayName))]
    public void CalculateTotal_EdgeCases(int quantity, decimal unitPrice, decimal expected)
    {
        var result = _calculator.CalculateTotal(quantity, unitPrice);
        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<object[]> EdgeCases => new[]
    {
        new object[] { int.MaxValue, 0.00m, 0.00m },
        new object[] { 1, decimal.MaxValue, decimal.MaxValue },
    };

    public static string GetDisplayName(MethodInfo _, object[] data)
        => $"Qty={data[0]}, Price={data[1]} → Expected={data[2]}";
}
```

**Key best practices shown:**

| Technique | When to use |
|-----------|-------------|
| `[DataRow]` | Simple inline constants (note: no `decimal` literals—use `double`) |
| `[DynamicData]` with Method | Complex types, computed values, or `decimal` precision |
| `DynamicDataDisplayName` | Readable test explorer names for dynamic cases |
| `[TestInitialize]` | Shared setup without constructor coupling |

**Tips:**
- `DataRow` only supports compile-time constants (`int`, `double`, `string`, `bool`, `Type`). Use `DynamicData` for `decimal` or object inputs.
- One assertion per test method keeps failure messages unambiguous.
- Group related `DataRow` sets by behavior (happy path, boundary, error).
